class MyModel(models.Model):
    _name = 'my.model'

    state = fields.Selection([('draft', 'Draft'), ('done', 'Done')], default='draft')
    amount = fields.Float()

    @api.onchange('amount')
    def _onchange_amount(self):
        if self.amount < 0:
            self.amount = 0
            return {'warning': {'title': 'Valeur invalide', 'message': 'Le montant ne peut pas être négatif.'}}
